import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Shape Detection","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/browsers/apis/shape-detection/README.md","filePath":"software-engineering/browsers/apis/shape-detection/README.md"}'),i={name:"software-engineering/browsers/apis/shape-detection/README.md"};function n(s,e,d,l,c,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="shape-detection" tabindex="-1">Shape Detection <a class="header-anchor" href="#shape-detection" aria-label="Permalink to &quot;Shape Detection&quot;">​</a></h1><h2 id="shape-detection-api-specification-movie-camera" tabindex="-1">Shape Detection API Specification 🌠:movie_camera: <a class="header-anchor" href="#shape-detection-api-specification-movie-camera" aria-label="Permalink to &quot;Shape Detection API Specification :stars::movie\\_camera:&quot;">​</a></h2><p>This is the repository for <code>shape-detection-api</code>, an experimental API for detecting Shapes (e.g. Faces, Barcodes, Text) in live or still images on the Web by <strong>using accelerated hardware/OS resources</strong>.</p><p>You&#39;re welcome to contribute! Let&#39;s make the Web rock our socks off!</p><h3 id="introduction-blue-book" tabindex="-1"><a href="https://wicg.github.io/shape-detection-api/#introduction" target="_blank" rel="noreferrer">Introduction</a> :blue_book: <a class="header-anchor" href="#introduction-blue-book" aria-label="Permalink to &quot;[Introduction](https://wicg.github.io/shape-detection-api/#introduction) :blue\\_book:&quot;">​</a></h3><p>Photos and images constitute the largest chunk of the Web, and many include recognisable features, such as human faces, text or QR codes. Detecting these features is computationally expensive, but would lead to interesting use cases e.g. face tagging or detection of high saliency areas. Users interacting with WebCams or other Video Capture Devices have become accustomed to camera-like features such as the ability to focus directly on human faces on the screen of their devices. This is particularly true in the case of mobile devices, where hardware manufacturers have long been supporting these features. Unfortunately, Web Apps do not yet have access to these hardware capabilities, which makes the use of computationally demanding libraries necessary.</p><h3 id="use-cases" tabindex="-1">Use cases 📷 <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases :camera:&quot;">​</a></h3><p>QR/barcode/text detection can be used for:</p><ul><li>user identification/registration, e.g. for <a href="https://twitter.com/RegistertoVote/status/733123511128981508" target="_blank" rel="noreferrer">voting purposes</a>;</li><li>eCommerce, e.g. <a href="https://www.slashgear.com/awalmart-announces-walmart-pay-for-qr-code-based-mobile-payments-10417912/" target="_blank" rel="noreferrer">Walmart Pay</a>;</li><li>Augmented Reality overlay, e.g. <a href="http://www.multidots.com/augmented-reality/" target="_blank" rel="noreferrer">here</a>;</li><li>Driving online-to-offline engagement, fighting fakes <a href="https://www.clickz.com/why-have-qr-codes-taken-off-in-china/23662/" target="_blank" rel="noreferrer">etc</a>.</li></ul><p>Face detection can be used for:</p><ul><li>producing fun effects, e.g. <a href="https://support.snapchat.com/en-US/a/lenses1" target="_blank" rel="noreferrer">Snapchat Lenses</a>;</li><li>giving hints to encoders or auto focus routines;</li><li>user name tagging;</li><li>enhance accesibility by e.g. making objects appear larger as the user gets closer like <a href="https://www.auduno.com/headtrackr/examples/targets.html" target="_blank" rel="noreferrer">HeadTrackr</a>;</li><li>speeding up Face Recognition by indicating the areas of the image where faces are present.</li></ul><h3 id="current-related-efforts-and-workarounds" tabindex="-1">Current Related Efforts and Workarounds 🔧 <a class="header-anchor" href="#current-related-efforts-and-workarounds" aria-label="Permalink to &quot;Current Related Efforts and Workarounds :wrench:&quot;">​</a></h3><p>Some Web Apps -gasp- run Detection in Javascript. A performance comparison of some such libraries can be found <a href="https://github.com/mtschirs/js-objectdetect#performance" target="_blank" rel="noreferrer">here</a> (note that this performance evaluation does not include e.g. WebCam image acquisition and/or canvas interactions).</p><p>Samsung Browser has a private API (click to unfold &quot;Overview for Android&quot;, then search for &quot;QR code reader&quot;).</p><p><strong>TODO</strong>: compare a few JS/native libraries in terms of size and performance. A performance and detection comparison of some popular JS QR code scanners can be found <a href="https://github.com/danimoh/qr-scanner-benchmark" target="_blank" rel="noreferrer">here</a>. <code>zxingjs2</code> has <a href="https://github.com/ghybs/zxingjs2#other-barcode-image-processing-libraries-related-to-javascript" target="_blank" rel="noreferrer">a list of some additional JS libraries</a>.</p><p>Android Native Apps usually integrate <a href="https://github.com/zxing/zxing" target="_blank" rel="noreferrer">ZXing</a> (which amounts to adding ~560KB when counting <a href="http://repo1.maven.org/maven2/com/google/zxing/core/3.3.0/" target="_blank" rel="noreferrer">core.jar</a>, <a href="http://repo1.maven.org/maven2/com/google/zxing/android-core/3.3.0/" target="_blank" rel="noreferrer">android-core.jar</a> and <a href="http://repo1.maven.org/maven2/com/google/zxing/android-integration/3.3.0/" target="_blank" rel="noreferrer">android-integration.jar</a>)).</p><p>OCR reader in Javascript are north of 1MB of size ()</p><h3 id="potential-for-misuse-money-with-wings" tabindex="-1">Potential for misuse :money_with_wings: <a class="header-anchor" href="#potential-for-misuse-money-with-wings" aria-label="Permalink to &quot;Potential for misuse :money\\_with\\_wings:&quot;">​</a></h3><p>Face Detection is an expensive operation due to the algorithmic complexity. Many requests, or demanding systems like a live stream feed with a certain frame rate, could slow down the whole system or greatly increase power consumption.</p><h3 id="platform-specific-implementation-notes" tabindex="-1">Platform specific implementation notes 💻 <a class="header-anchor" href="#platform-specific-implementation-notes" aria-label="Permalink to &quot;Platform specific implementation notes :computer:&quot;">​</a></h3><h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>What platforms support what detector?</p><table tabindex="0"><thead><tr><th>Encoder</th><th style="text-align:center;">Mac</th><th style="text-align:center;">Android</th><th style="text-align:center;">Win10</th><th style="text-align:center;">Linux</th><th style="text-align:center;">ChromeOs</th></tr></thead><tbody><tr><td>Face</td><td style="text-align:center;">sw</td><td style="text-align:center;">hw/sw</td><td style="text-align:center;">sw</td><td style="text-align:center;">✘</td><td style="text-align:center;">✘</td></tr><tr><td>QR/Barcode</td><td style="text-align:center;">sw</td><td style="text-align:center;">sw</td><td style="text-align:center;">✘</td><td style="text-align:center;">✘</td><td style="text-align:center;">✘</td></tr><tr><td>Text</td><td style="text-align:center;">sw</td><td style="text-align:center;">sw</td><td style="text-align:center;">sw</td><td style="text-align:center;">✘</td><td style="text-align:center;">✘</td></tr></tbody></table><h4 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h4><p>Android provides both a stand alone software face detector and a interface to the hardware ones.</p><table tabindex="0"><thead><tr><th>API</th><th style="text-align:center;">uses...</th><th style="text-align:right;">Release notes</th></tr></thead><tbody><tr><td><a href="https://developer.android.com/reference/android/media/FaceDetector.html" target="_blank" rel="noreferrer">FaceDetector</a></td><td style="text-align:center;">Software based using the <a href="https://android.googlesource.com/platform/external/neven" target="_blank" rel="noreferrer">Neven face detector</a></td><td style="text-align:right;">API Level 1, 2008</td></tr><tr><td><a href="https://developers.google.com/android/reference/com/google/android/gms/vision/face/Face" target="_blank" rel="noreferrer">Vision.Face</a></td><td style="text-align:center;">Software based</td><td style="text-align:right;">Google Play services 7.2, Aug 2015</td></tr><tr><td><a href="https://developer.android.com/reference/android/hardware/camera2/CaptureRequest.html#STATISTICS_FACE_DETECT_MODE" target="_blank" rel="noreferrer">Camera2</a></td><td style="text-align:center;">Hardware</td><td style="text-align:right;">API Level 21/Lollipop, 2014</td></tr><tr><td><a href="https://developer.android.com/reference/android/hardware/Camera.Face.html" target="_blank" rel="noreferrer">Camera.Face</a> (old)</td><td style="text-align:center;">Hardware</td><td style="text-align:right;">API Level 14/Ice Cream Sandwich, 2011</td></tr></tbody></table><p>The availability of the actual hardware detection depends on the actual chip; according to the market share in <a href="http://www.antutu.com/en/view.shtml?id=8256" target="_blank" rel="noreferrer">1H 2016</a> Qualcomm, MediaTek, Samsung and HiSilicon are the largest individual OEMs and they all have support for Face Detection (all the top-10 phones are covered as well):</p><ul><li><a href="https://developer.qualcomm.com/software/snapdragon-sdk-android/facial-recognition" target="_blank" rel="noreferrer">Qualcomm Snapdragon</a> chipset family supports it since ~2013 as part of their ISP.</li><li>MediaTek as part of <a href="http://cdn-cw.mediatek.com/White%20Papers/MediaTek_CorePilot%202.0_Final.pdf" target="_blank" rel="noreferrer">CorePilot 2.0</a> (introduced in 2015).</li><li><a href="http://www.samsung.com/semiconductor/minisite/Exynos/data/Benefits_of_Exynos_5420_ISP_for_Enhanced_Imaging_Experience.pdf" target="_blank" rel="noreferrer">Samsung Exynos</a> (at least 2013).</li><li>Huawei HiSilicon <a href="http://www.androidauthority.com/huawei-hisilicon-kirin-950-official-653811" target="_blank" rel="noreferrer">Kirin950</a> since 2015 (this fabless manufacturer is relatively new).</li><li>It is worth noting that ARM <a href="https://www.arm.com/products/graphics-and-multimedia/computer-vision" target="_blank" rel="noreferrer">acquired Apical in 2016</a> for its computer vision expertise.</li></ul><p>Barcode/QR and Text detection is available via Google Play Services <a href="https://developers.google.com/android/reference/com/google/android/gms/vision/barcode/package-summary" target="_blank" rel="noreferrer">barcode</a> and <a href="https://developers.google.com/android/reference/com/google/android/gms/vision/text/package-summary" target="_blank" rel="noreferrer">text</a>, respectively.</p><h4 id="mac-os-x-ios" tabindex="-1">Mac OS X / iOS <a class="header-anchor" href="#mac-os-x-ios" aria-label="Permalink to &quot;Mac OS X / iOS&quot;">​</a></h4><p>Mac OS X/iOS provides <code>CIDetector</code> and <code>Vision Framework</code> for Face, QR, Text and Rectangle detection in software or hardware.</p><table tabindex="0"><thead><tr><th>API</th><th style="text-align:center;">uses...</th><th style="text-align:right;">Release notes</th></tr></thead><tbody><tr><td><a href="https://developer.apple.com/documentation/vision" target="_blank" rel="noreferrer">Vision Framework, Mac OS X</a></td><td style="text-align:center;">Software and Hardware</td><td style="text-align:right;">OS X v10.13, 2017</td></tr><tr><td><a href="https://developer.apple.com/documentation/vision" target="_blank" rel="noreferrer">Vision Framework, iOS</a></td><td style="text-align:center;">Software and Hardware</td><td style="text-align:right;">IOS X v11.0, 2017</td></tr><tr><td><a href="https://developer.apple.com/library/mac/documentation/CoreImage/Reference/CIDetector_Ref/" target="_blank" rel="noreferrer">CIDetector, Mac OS X</a></td><td style="text-align:center;">Software</td><td style="text-align:right;">OS X v10.7, 2011</td></tr><tr><td><a href="https://developer.apple.com/library/ios/documentation/CoreImage/Reference/CIDetector_Ref/" target="_blank" rel="noreferrer">CIDetector, iOS</a></td><td style="text-align:center;">Software</td><td style="text-align:right;">iOS v5.0, 2011</td></tr><tr><td><a href="https://developer.apple.com/reference/avfoundation/avcapturemetadataoutput?language=objc" target="_blank" rel="noreferrer">AVFoundation</a></td><td style="text-align:center;">Hardware</td><td style="text-align:right;">iOS 6.0, 2012</td></tr></tbody></table><p>Apple has supported Face Detection in hardware since the <a href="https://en.wikipedia.org/wiki/Apple_A5" target="_blank" rel="noreferrer">Apple A5 processor</a> introduced in 2011.</p><h4 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h4><p>Windows 10 has a <a href="https://msdn.microsoft.com/library/windows/apps/dn974129" target="_blank" rel="noreferrer">FaceDetector</a> class and support for Text Detection <a href="https://msdn.microsoft.com/en-us/library/windows/apps/windows.media.ocr.aspx" target="_blank" rel="noreferrer">OCR</a>.</p><h3 id="rendered-url-bookmark-tabs" tabindex="-1">Rendered URL :bookmark_tabs: <a class="header-anchor" href="#rendered-url-bookmark-tabs" aria-label="Permalink to &quot;Rendered URL :bookmark\\_tabs:&quot;">​</a></h3><p>The rendered version of this site can be found in <a href="https://wicg.github.io/shape-detection-api" target="_blank" rel="noreferrer">https://wicg.github.io/shape-detection-api</a> (if that&#39;s not alive for some reason try the <a href="https://rawgit.com/WICG/shape-detection-api/gh-pages/index.html" target="_blank" rel="noreferrer">rawgit rendering</a>).</p><h3 id="examples-and-demos" tabindex="-1">Examples and demos <a class="header-anchor" href="#examples-and-demos" aria-label="Permalink to &quot;Examples and demos&quot;">​</a></h3><p><a href="https://wicg.github.io/shape-detection-api/#examples" target="_blank" rel="noreferrer">https://wicg.github.io/shape-detection-api/#examples</a></p><h3 id="notes-on-bikeshedding" tabindex="-1">Notes on bikeshedding 🚴 <a class="header-anchor" href="#notes-on-bikeshedding" aria-label="Permalink to &quot;Notes on bikeshedding :bicyclist:&quot;">​</a></h3><p>To compile, run:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl https://api.csswg.org/bikeshed/ -F file=@index.bs -F force=1 &gt; index.html</span></span></code></pre></div><p>if the produced file has a strange size (i.e. zero), then something went terribly wrong; run instead</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl https://api.csswg.org/bikeshed/ -F file=@index.bs -F output=err</span></span></code></pre></div><p>and try to figure out why <code>bikeshed</code> did not like the <code>.bs</code> 😢</p>',45)])])}const m=t(i,[["render",n]]);export{g as __pageData,m as default};
